/**
 * @summary Chronological audit trail of every status transition recorded for
the ticket. Backed by `ticket_status_history`. Reasons that
reference vendor IDs (the partner-self-service reinvite flow
records `reassigned from vendor #X to vendor #Y`) are enriched
server-side so the UI can render vendor names without a follow-up
round-trip.

Task #857: optional query filters mirror the Audit Trail filter
chips on the web ticket-detail page (kind/actorRole/from/to).
Filtering is applied server-side so a CSV export can be produced
from exactly the same row set the UI is showing. The CSV form
is requested by appending `?format=csv` to the same URL.

 */
export const getGetTicketTransitionsUrl = (
  id: number,
  params?: GetTicketTransitionsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    const explodeParameters = ["kind", "actorRole"];

    if (Array.isArray(value) && explodeParameters.includes(key)) {
      value.forEach((v) => {
        normalizedParams.append(key, v === null ? "null" : v.toString());
      });
      return;
    }

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/tickets/${id}/transitions?${stringifiedParams}`
    : `/api/tickets/${id}/transitions`;
};

export const getTicketTransitions = async (
  id: number,
  params?: GetTicketTransitionsParams,
  options?: RequestInit,
): Promise<TicketTransition[] | string> => {
  return customFetch<TicketTransition[] | string>(
    getGetTicketTransitionsUrl(id, params),
    {
      ...options,
      method: "GET",
    },
  );
};

